)

// FIX 3: Check for browser environment
function SafeComponent() {
  const [isClient, setIsClient] = useState(false)

  useEffect(() => {
    setIsClient(true)
  }, [])

  if (!isClient) {
    return <div className="h-10 bg-muted animate-pulse rounded" />
  }

  return <ComplexInteractiveWidget />
}
